import base64

# Your base64 QR code string (replace this with yours)
qr_code_base64 = """

"""

# Decode the base64 string
image_data = base64.b64decode(qr_code_base64)

# Save it as an image
output_filename = "decoded_qr.png"
with open(output_filename, "wb") as f:
    f.write(image_data)

print(f"✅ QR code image saved successfully as {output_filename}")
